import {
    useConnectWallet,
    useWallets,
    useCurrentAccount,
    useDisconnectWallet,
} from '@iota/dapp-kit';
import { ItemsLoader } from './ItemsLoader.tsx';
import { Introduction } from './Introduction.tsx';
import { useState } from 'react';
import {
  CreateContainerForm,
  AddOwnerForm,
  RemoveOwnerForm,
  AttachChildForm,
  CreateDataTypeForm,
  PublishDataItemForm,
  UpdateContainerForm,
  UpdateDataTypeForm,
} from './MoveForms.tsx';
import './style/Index.css';
import './App.tsx';
type FormType =
  | 'create_container'
  | 'add_owner'
  | 'remove_owner'
  | 'attach_child'
  | 'create_data_type'
  | 'publish_data_item'
  | 'update_container'
  | 'update_data_type';

export function GenericStorePage({ address }: { address: string }) {
  const [activeForm, setActiveForm] = useState<FormType>('create_container');

  return (
    <div>
      <h2>Generic Store</h2>

      {/* selector */}
      <select
        value={activeForm}
        onChange={(e) => setActiveForm(e.target.value as FormType)}
      >
        <option value="create_container">Create Container</option>
        <option value="add_owner">Add Owner</option>
        <option value="remove_owner">Remove Owner</option>
        <option value="attach_child">Attach Child</option>
        <option value="create_data_type">Create Data Type</option>
        <option value="publish_data_item">Publish Data Item</option>
        <option value="update_container">Update Container</option>
        <option value="update_data_type">Update Data Type</option>
      </select>

      <hr />

      {/* render exactly ONE form */}
      {activeForm === 'create_container' && (
        <CreateContainerForm address={address} />
      )}
      {activeForm === 'add_owner' && <AddOwnerForm address={address} />}
      {activeForm === 'remove_owner' && <RemoveOwnerForm address={address} />}
      {activeForm === 'attach_child' && <AttachChildForm address={address} />}
      {activeForm === 'create_data_type' && (
        <CreateDataTypeForm address={address} />
      )}
      {activeForm === 'publish_data_item' && (
        <PublishDataItemForm address={address} />
      )}
      {activeForm === 'update_container' && (
        <UpdateContainerForm address={address} />
      )}
      {activeForm === 'update_data_type' && (
        <UpdateDataTypeForm address={address} />
      )}
    </div>
  );
}
export default function App() {
    const account = useCurrentAccount();
    const { mutate: disconnect } = useDisconnectWallet();

    return (
        <div>
            <header className="navbar">
                <div className="logo">BlockPublisher</div>
                <div className="nav-right">
                                           {!account && <UseConnectWalletExample />}
                              {account && (
                        <>
                            <p>Connected as: {shortenAddressWithCopy(account.address)}</p>
                            <button className="btn secondary" onClick={() => disconnect()}>Disconnect</button>
                        </>
                    )}
                    <nav>
                    <a href="#features">Features</a>
                    <a href="#api">API</a>
                    <a href="#architecture">Architecture</a>
                    <a href="#cta" className="btn">Get Started</a>

                </nav>

                    </div>
            </header> 

            {account && (

                  GenericStorePage({account.address})

                <ItemsLoader
                    containerId="0x139b35c2c3e23bfdfbbde3576c71c7af50a3e75cb708743237e17dd1ad2901c8"
                    type="data_item"
                />
            )};

            {!account && (
                <Introduction />
            )}

            <footer className="footer">
                <p>© 2026 BlockPublisher · Built on IOTA</p>
            </footer>
        </div>

    );
}

function UseConnectWalletExample() {
    const wallets = useWallets();
    const { mutate: connect } = useConnectWallet();

    return (
            wallets.map((wallet) => (
                        <button className="btn secondary"
                            onClick={() => {
                                connect(
                                    { wallet },
                                    {
                                        onSuccess: () => console.log('connected'),
                                    },
                                );
                            }}
                        >
                            Connect to {wallet.name}
                        </button>
                ))
    );
}
function shortenAddressWithCopy(
  address: string,
  start: number = 6,
  end: number = 4
) {
  if (!address) return '';

  const short =
    address.length <= start + end
      ? address
      : `${address.slice(0, start)}…${address.slice(-end)}`;

  return (
    <span className="addr-wrap" title="${address}">
      <span className="addr-short">{short}</span>
      <span
        className="addr-copy"
        onClick={() => {navigator.clipboard.writeText(address)}}
        title="Copy address"
      >
        📋
      </span>
    </span>
  );
}


